import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o as l,c as o,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Блог","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/blog.md","filePath":"ru-RU/Other/blog.md","lastUpdated":1781962217000}'),n={name:"ru-RU/Other/blog.md"};function d(c,a,r,h,g,b){return l(),o("div",null,[...a[0]||(a[0]=[p('<h1 id="блог" tabindex="-1">Блог <a class="header-anchor" href="#блог" aria-label="Permalink to &quot;Блог&quot;">​</a></h1><p>Функция блога добавляет на сайт ImgBed отдельную страницу блога.</p><p>После включения посетители могут открыть:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Главная страница блога" loading="lazy"></p><p>Блог адаптирован из open-source проекта <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed переписывает и интегрирует его с Vue, чтобы он работал как часть сайта изображений.</p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Настройки блога находятся здесь:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="Настройки блога" loading="lazy"></p><h2 id="первичная-настроика" tabindex="-1">Первичная настройка <a class="header-anchor" href="#первичная-настроика" aria-label="Permalink to &quot;Первичная настройка&quot;">​</a></h2><ol><li>Включите <code>Enable</code>.</li><li>Выберите GitHub-аккаунт, где будет храниться конфигурация блога.</li><li>Нажмите <code>Update Blog</code>.</li><li>Дождитесь сообщения об успехе.</li><li>Откройте <code>https://your-domain.com/blog/</code>, чтобы посмотреть блог.</li></ol><p>При первом использовании ImgBed подготовит приватный GitHub-репозиторий в выбранном аккаунте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>В этом репозитории хранятся настройки блога и тексты статей.</p><h2 id="написание-постов" tabindex="-1">Написание постов <a class="header-anchor" href="#написание-постов" aria-label="Permalink to &quot;Написание постов&quot;">​</a></h2><p>Редактируйте посты блога в своем приватном GitHub-репозитории:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Обычный процесс:</p><ol><li>Откройте GitHub.</li><li>Перейдите в приватный репозиторий <code>imgbed-blog-config</code>.</li><li>Отредактируйте или добавьте файлы постов.</li><li>Закоммитьте изменения.</li><li>Вернитесь в админ-панель ImgBed и нажмите <code>Update Blog</code>, либо трижды нажмите логотип в левом верхнем углу главной страницы блога, чтобы запустить обновление.</li></ol><p><code>Update Blog</code> не перезаписывает написанный вами контент. Он инициализирует репозиторий при необходимости и обновляет кеш блога.</p><h2 id="поддерживаемые-возможности" tabindex="-1">Поддерживаемые возможности <a class="header-anchor" href="#поддерживаемые-возможности" aria-label="Permalink to &quot;Поддерживаемые возможности&quot;">​</a></h2><p>Блог поддерживает типичные функции: список постов, категории, теги, архив, поиск, темный режим и переключение языка.</p><p>Также поддерживаются комментарии и статистика посещений.</p><p><img src="'+i+'" alt="Комментарии блога" loading="lazy"></p><p>Комментарии показываются под постами. Посетители могут указать avatar, nickname, email и текст комментария.</p><p>Статистика посещений показывает просмотры постов и визиты сайта, помогая понимать трафик блога.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Блог всегда доступен по пути <code>/blog/</code>.</p><p>Например, если домен ImgBed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>URL блога будет:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>После выключения блога посетители больше не смогут открыть страницу блога.</p>',34)])])}const k=s(n,[["render",d]]);export{v as __pageData,k as default};
